mapper.select:
select count(1) from hrm_employee_contacts_data a
left join hrm_employee_contacts b on a.contacts_id = b.contacts_id
left join hrm_employee c on b.employee_id = c.employee_id
where c.is_del = 0 and a.field_id = #{fieldId} and a.field_value = #{value}

    and a.contacts_id != #{contactsId}
